1. Create src/components/sections/Hero.astro:

```astro
---
import Container from "../ui/Container.astro";
import HeroAnimation from "./HeroAnimation";
import ScrollIndicator from "../ui/ScrollIndicator";

interface Props {
  title: string;
  subtitle?: string;
  backgroundImage?: string;
  showScrollIndicator?: boolean;
  scrollTargetId?: string;
}

const {
  title,
  subtitle,
  backgroundImage = "/images/hero-bg.jpg",
  showScrollIndicator = true,
  scrollTargetId = "services",
} = Astro.props;
---

<section
  class="relative min-h-screen flex items-center justify-center overflow-hidden"
  aria-label="ヒーローセクション"
>
  {/* Background Image with Overlay */}
  <div class="absolute inset-0 z-0">
    <div
      class="absolute inset-0 bg-cover bg-center bg-no-repeat"
      style={`background-image: url('${backgroundImage}')`}
      role="img"
      aria-label="背景画像"
    >
    </div>
    {/* Gradient Overlay for contrast */}
    <div class="absolute inset-0 bg-gradient-to-b from-black/60 via-black/40 to-black/60"></div>
  </div>

  {/* Content */}
  <Container class="relative z-10 text-center py-20">
    <HeroAnimation client:visible>
      <h1 class="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-bold text-white leading-tight mb-6">
        {title}
      </h1>
      {subtitle && (
        <p class="text-lg sm:text-xl md:text-2xl text-white/90 max-w-3xl mx-auto mb-8">
          {subtitle}
        </p>
      )}
      <slot />
    </HeroAnimation>
  </Container>

  {/* Scroll Indicator */}
  {showScrollIndicator && (
    <div class="absolute bottom-8 left-1/2 -translate-x-1/2 z-10">
      <ScrollIndicator client:visible targetId={scrollTargetId} />
    </div>
  )}
</section>
```

2. Create src/components/sections/HeroAnimation.tsx:

```tsx
import { useRef, useEffect, type ReactNode } from "react";
import { animate, stagger } from "motion";

interface HeroAnimationProps {
  children: ReactNode;
}

export default function HeroAnimation({ children }: HeroAnimationProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // Check for reduced motion preference
    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;

    if (prefersReducedMotion) {
      // Just show content immediately
      const elements = container.querySelectorAll(".hero-animate-item");
      elements.forEach((el) => {
        (el as HTMLElement).style.opacity = "1";
      });
      return;
    }

    // Get all direct children to animate
    const elements = container.children;

    // Set initial state
    Array.from(elements).forEach((el) => {
      (el as HTMLElement).style.opacity = "0";
      (el as HTMLElement).style.transform = "translateY(30px)";
    });

    // Animate each child with stagger
    animate(
      Array.from(elements),
      { opacity: [0, 1], y: [30, 0] },
      {
        duration: 0.6,
        easing: [0.4, 0, 0.2, 1],
        delay: stagger(0.15),
      }
    );
  }, []);

  return (
    <div ref={containerRef} className="hero-animation-container">
      {children}
    </div>
  );
}
```

