     1→import { inView, animate } from "motion";
     2→
     3→/**
     4→ * Check if user prefers reduced motion
     5→ */
     6→export const prefersReducedMotion = (): boolean => {
     7→  if (typeof window === "undefined") return false;
     8→  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
     9→};
    10→
    11→/**
    12→ * Animation directions for fade in
    13→ */
    14→export const fadeDirections = {
    15→  up: { y: [30, 0] },
    16→  down: { y: [-30, 0] },
    17→  left: { x: [30, 0] },
    18→  right: { x: [-30, 0] },
    19→} as const;
    20→
    21→export type FadeDirection = keyof typeof fadeDirections;
    22→
    23→/**
    24→ * Default animation config
    25→ */
    26→export const defaultAnimationConfig = {
    27→  duration: 0.5,
    28→  easing: [0.4, 0, 0.2, 1] as [number, number, number, number],
    29→};
    30→
    31→/**
    32→ * Initialize fade-in animations for elements with .animate-on-scroll class
    33→ */
    34→export const initFadeInAnimations = (): void => {
    35→  if (prefersReducedMotion()) return;
    36→
    37→  inView(
    38→    ".animate-on-scroll",
    39→    (element) => {
    40→      const direction = (element.getAttribute("data-direction") || "up") as FadeDirection;
    41→      const delay = parseFloat(element.getAttribute("data-delay") || "0");
    42→
    43→      animate(
    44→        element,
    45→        {
    46→          opacity: [0, 1],
    47→          ...fadeDirections[direction]
    48→        },
    49→        {
    50→          duration: defaultAnimationConfig.duration,
    51→          easing: defaultAnimationConfig.easing,
    52→          delay,
    53→        }
    54→      );
    55→    },
    56→    { amount: 0.2 }
    57→  );
    58→};
    59→
    60→/**
    61→ * Dynamic GSAP loader for CountUp component
    62→ * Only loads GSAP when needed to minimize bundle size
    63→ */
    64→export const loadGSAP = async () => {
    65→  const [gsapModule, scrollTriggerModule] = await Promise.all([
    66→    import("gsap"),
    67→    import("gsap/ScrollTrigger"),
    68→  ]);
    69→
    70→  const gsap = gsapModule.default;
    71→  const { ScrollTrigger } = scrollTriggerModule;
    72→
    73→  gsap.registerPlugin(ScrollTrigger);
    74→
    75→  return { gsap, ScrollTrigger };
    76→};
    77→
