    79→ * Hero animation config
    80→ */
    81→export const heroAnimationConfig = {
    82→  initial: { opacity: 0, y: 30 },
    83→  animate: { opacity: 1, y: 0 },
    84→  transition: { duration: 0.5, ease: [0.4, 0, 0.2, 1] },
    85→};
    86→
